{
  "type": "QUIZ",
  "lessonText": "Test your knowledge of Python basics with this quiz.",
  "data": {
    "questions": [
      {
        "question": "What is the correct way to create a variable in Python?",
        "options": ["var x = 10", "x := 10", "x = 10", "10 = x"],
        "correctAnswer": 2,
        "explanation": "In Python, variables are created using the assignment operator '='."
      },
      {
        "question": "Which of the following is a valid Python list?",
        "options": ["[1, 2, 3]", "(1, 2, 3)", "{1, 2, 3}", "<1, 2, 3>"],
        "correctAnswer": 0,
        "explanation": "Lists in Python are defined using square brackets []."
      },
      {
        "question": "How do you define a function in Python?",
        "options": ["function myFunc()", "def myFunc()", "myFunc() = function", "myFunc() => function"],
        "correctAnswer": 1,
        "explanation": "Functions in Python are defined using the 'def' keyword."
      },
      {
        "question": "Which of the following is used to comment in Python?",
        "options": ["// comment", "# comment", "<!-- comment -->", "/* comment */"],
        "correctAnswer": 1,
        "explanation": "Single-line comments in Python start with the '#' symbol."
      }
    ]
  }
}
